    "monitoring_coverage": "Insufficient. DB query duration and error count are good starts but missing: connection pool metrics, HTTP-level metrics, and health of replica lag. An operator cannot assess system health from current metrics alone.",
    "on_call_documentation": "Not mentioned. At minimum need: runbook for primary failover (manual restart procedure), runbook for pool exhaustion, escalation path for sustained error rates, and expected baseline metrics.",
    "new_infrastructure_required": {
      "new_env_vars": [
        "DATABASE_REPLICA_URL — read replica connection string for read routing",
        "DB_CONNECTION_TIMEOUT — configurable connection timeout (currently not set)",
        "DB_QUERY_TIMEOUT — configurable statement timeout"
      ],
      "new_services": [
        "Consider PgBouncer or connection proxy for transparent failover handling"
      ],
      "new_queues_topics": [],
      "config_changes": [
        "Connection string must be dynamically resolvable (DNS-based or config reload) instead of baked into app config",
        "Add statement_timeout to PostgreSQL connection parameters",
        "Add pool_pre_ping or equivalent connection validation to detect stale connections"
      ],
      "infra_provisioning": []
    },
    "database_safety": {
      "has_migrations": false,
      "reversible": false,
      "data_preserving": true,
      "large_table_impact": false,
      "details": "No schema changes mentioned. Service is a new consumer of existing order data. Primary concern is load impact — routing all reads to primary instead of replicas adds unnecessary pressure to the write leader."
